starterCode.css:
.notification-container {
  @apply fixed inset-0 z-10 bg-gray-900 bg-opacity-50 flex lg:flex-row lg:justify-center lg:items-center;
}
.notification {
  @apply bg-orange-500 text-white p-4 rounded shadow-md flex flex-col;
}
.close-notification {
  @apply float-right hover:bg-orange-600 rounded transition bg-orange-500 text-white p-1 cursor-pointer;
}
#notification-message {
  @apply font-bold text-lg mb-2;
}

